// Group assignments by staff email and build schedule summary
const data = $input.first().json;
const assignments = data.assignments || [];
const restaurant = data.restaurant;
const weekStart = data.shiftPlan.weekStartDate;

// Group by staff
const byStaff = {};
for (const a of assignments) {
  const key = a.staffEmail || a.staffName || a.staffMemberId;
  if (!byStaff[key]) {
    byStaff[key] = {
      staffName: a.staffName || 'Staff',
      staffEmail: a.staffEmail || '',
      shifts: []
    };
  }
  byStaff[key].shifts.push({
    day: a.day || a.date,
    shiftName: a.shiftName,
    start: a.shiftStart,
    end: a.shiftEnd,
    role: a.role,
    hours: a.hours
  });
}

// Build output items — one per staff member
const items = Object.values(byStaff).map(staff => {
  const shiftLines = staff.shifts.map(s => 
    `<tr><td style="padding:6px 12px;border-bottom:1px solid #eee;">${s.day}</td><td style="padding:6px 12px;border-bottom:1px solid #eee;">${s.shiftName}</td><td style="padding:6px 12px;border-bottom:1px solid #eee;">${s.start} — ${s.end}</td><td style="padding:6px 12px;border-bottom:1px solid #eee;">${s.hours}h</td></tr>`
  ).join('');

  const totalHours = staff.shifts.reduce((sum, s) => sum + (s.hours || 0), 0);

  const html = `<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:600px;margin:0 auto;padding:30px 20px;">
    <h2>📅 Your Shift Schedule</h2>
    <p>Hi ${staff.staffName}, here is your schedule for the week of ${weekStart}:</p>
    <table style="width:100%;border-collapse:collapse;margin:20px 0;">
      <tr style="background:#f9f9f9;"><th style="padding:8px 12px;text-align:left;">Day</th><th style="padding:8px 12px;text-align:left;">Shift</th><th style="padding:8px 12px;text-align:left;">Time</th><th style="padding:8px 12px;text-align:left;">Hours</th></tr>
      ${shiftLines}
    </table>
    <p><strong>Total hours this week:</strong> ${totalHours}h</p>
    <hr style="border:none;border-top:1px solid #eee;margin:24px 0;">
    <p style="color:#aaa;font-size:11px;">${restaurant.name}</p>
  </div>`;

  return {
    json: {
      staffName: staff.staffName,
      staffEmail: staff.staffEmail,
      subject: `📅 Your shifts for week of ${weekStart} — ${restaurant.name}`,
      html,
      restaurant
    }
  };
});

return items;
